// turn on IR
#define ON do { TCCR2A |= _BV(COM2B1); } while(0)

// turn off IR
#define OFF do { \
                   TCCR2A &= ~_BV(COM2B1); \
                   PORT_IR &= ~(_BV(PIN_IR)); \
               } while(0)

void ir_setup() {
    DDRD |= _BV(DDD3);

    // 38KHz PWM at 50%
    TCCR2A = _BV(WGM20);
    TCCR2B = _BV(WGM22) | _BV(CS20);
    OCR2A = 210;
    OCR2B = 105;

    // make sure its off
    OFF;
}

// NOTE i do not know if its critical to avoid digitalWrite but its it takes
// few microseconds so just to be safe, im using raw AVR
inline void send_ir(int16_t* mem, uint16_t size) {
    int16_t duration = 0;
    for (uint16_t i = 0; i < size; i++) {
        duration = (int16_t)pgm_read_word(mem + i);
        if (duration > 0) {
            ON;
        } else if (duration < 0) {
            OFF;
        }

        delayMicroseconds(abs(duration));
    }

    // make sure its off
    OFF;
}

void ac_on() {
    send_ir((int16_t*)IR_ON, IR_ON_LEN);
}

void ac_off() {
    send_ir((int16_t*)IR_OFF, IR_OFF_LEN);
}

void ac_fan() {
    send_ir((int16_t*)IR_FAN, IR_FAN_LEN);
}

